需求利用tweepy和hashtag爬取推文（每个hash拿500条左右）对推文进行文本处理：去非英文字符、去链接、去hash、去中止词以hash:twitter形式存字典再存文件：dict_hash_twitter 推文采集由于国内网络环境问题，还是把每个hash对应的推文保存成文件再处理，稳点起见。事实证明，用tweepy包的search方法会有访问频率限制，但我申请了四个twitter app轮回换key还是能实现不间断下载的 get_twitter.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475import tweepyfrom tweepy import OAuthHandlerimport relist_consumer_key = [&apos;########################&apos;, &apos;########################&apos;, &apos;########################&apos;, &apos;########################&apos;]list_consumer_secret = [&apos;########################&apos;, &apos;########################&apos;, &apos;########################&apos;, &apos;########################&apos;]list_access_token = [&apos;########################-########################&apos;, &apos;########################-########################&apos;, &apos;########################-########################&apos;, &apos;########################-########################&apos;]list_access_secret = [&apos;########################&apos;, &apos;########################&apos;, &apos;########################&apos;, &apos;########################&apos;]num_key = 0consumer_key = list_consumer_key[num_key]consumer_secret = list_consumer_secret[num_key]access_token = list_access_token[num_key]access_secret = list_access_secret[num_key]auth = OAuthHandler(consumer_key, consumer_secret)auth.set_access_token(access_token, access_secret)# api = tweepy.API(auth) # 不使用代理api = tweepy.API(auth, proxy=&quot;127.0.0.1:1080&quot;)f_hash = open(&quot;count_hash.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)list_hash = []while 1: line_hash = f_hash.readline() if not line_hash: break else: list_hash.append(str(re.findall(r&quot;&apos;(.*?)&apos;&quot;, line_hash, flags=0)[0]))print(&apos;list_hash生成成功：&apos; + str(len(list_hash)))for id in range(1056, len(list_hash)): try: query = str(list_hash[id]) print(query) # 获取推文 tweets = tweepy.Cursor(api.search, q=query, count=100, lang=&apos;en&apos;, include_entities=False).items(300) f_twitter = open(&quot;./hash_twitter/&quot; + str(list_hash[id]), &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) i = 0 for tweet in tweets: f_twitter.write(str(tweet.text).replace(&apos;
&apos;, &apos; &apos;) + &apos;
&apos;) i += 1 print(i) if (i &lt; 300): f_short_hash = open(&quot;short_hash.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_short_hash.write(str(list_hash[id]) + &apos;
&apos;) f_short_hash.close() print(id) except(TypeError, tweepy.error.TweepError): print(str(list_hash[id]) + &apos;爬取失败&apos;) f_error_hash = open(&quot;error_hash.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_error_hash.write(str(list_hash[id]) + &apos;
&apos;) f_error_hash.close() # 更换key num_key += 1 if (num_key == 4): num_key = 0 consumer_key = list_consumer_key[num_key] consumer_secret = list_consumer_secret[num_key] access_token = list_access_token[num_key] access_secret = list_access_secret[num_key] auth = OAuthHandler(consumer_key, consumer_secret) auth.set_access_token(access_token, access_secret) api = tweepy.API(auth, proxy=&quot;127.0.0.1:1080&quot;) print(&apos;key更换成功，继续下载-------------------------&gt;&apos;) 数据处理下载好的文件是多行的推文需要对推文进行文本处理：去非英文字符、去链接、去hash、去中止词然后以hash为文件名以一行处理后的推文为内容存文件 clean_data.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596import reimport osdef get_hashs(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListdef file_name(file_dir): # 获取视频名list for root, dirs, files in os.walk(file_dir): continue return filesdef is_alpha(word): try: return word.encode(&apos;ascii&apos;).isalpha() except UnicodeEncodeError: return Falsef_stop_word = open(&quot;stop_word.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)list_stop_word = []while 1: line_stop_word = f_stop_word.readline() if not line_stop_word: break else: list_stop_word.append(str(line_stop_word).replace(&quot;
&quot;, &apos;&apos;).lower())print(&quot;停用词列表生成成功:&quot; + str(len(list_stop_word)))list_hash_down = file_name(r&apos;I:\推荐系统\数据集	witter\hash_twitter&apos;)print(len(list_hash_down))for hash in list_hash_down: f_twitter = open(&apos;./hash_twitter/&apos; + hash, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) long_str = &apos;&apos; # for i in range(1, 10): while 1: line_twitter = f_twitter.readline() if not line_twitter: break else: line_twitter = re.sub(r&apos;#\w* &apos;, &apos;&apos;, line_twitter) line_twitter = re.sub(r&apos;#\w*
&apos;, &apos;&apos;, line_twitter) line_twitter = re.sub(r&apos;https\S* &apos;, &apos;&apos;, line_twitter) line_twitter = re.sub(r&apos;https\S*
&apos;, &apos;&apos;, line_twitter) text_final = &apos;&apos; for s in line_twitter: if is_alpha(s): text_final += s elif s == &apos; &apos; or s == &apos;-&apos; or s == &apos;~&apos;: text_final += &apos; &apos; # 去除非英文字符，保留空格 text_final = re.sub(r&apos;\s+&apos;, &apos; &apos;, text_final) line_twitter = text_final.lower() list_word = line_twitter.split(&apos; &apos;) # 分词，包含空字符 text_final = &apos;&apos; for word in list_word: if word == &apos;&apos;: continue elif word not in list_stop_word: # 去除中止词 text_final += word + &apos; &apos; long_str += text_final f_twitter.close() long_str = re.sub(r&apos;
&apos;, &apos;&apos;, long_str) long_str = re.sub(r&apos;\s+&apos;, &apos; &apos;, long_str) list_word = long_str.split(&apos; &apos;) if (len(list_word) &lt; 10): print(str(hash) + &apos;太短&apos;) f_short_result = open(&apos;short_result&apos;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_short_result.write(str(hash) + &apos;
&apos;) f_short_result.close() else: f_twitter_new = open(&apos;./hash_twitter_new/&apos; + hash, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_twitter_new.write(long_str) f_twitter_new.close()

需求&amp;前提多个文件夹的视频文件共121117-1862（下载失败数）= 119255 条多个文件夹的分割后文件共119255 - 135（分割失败数）= 119120 条现要对这119120条数据做hash词频统计，并截取词频不小于5的所有数据并清除不合法数据 求得分割后数据数:遍历video文件夹建立list_id并去除extract_fail数据 get_all_videos.py123456789101112131415161718192021222324252627282930313233343536373839404142434445# 获取所有拆分成功的短视频id存入list_id.txtimport osdef file_name(file_dir): # 获取视频名list for root, dirs, files in os.walk(file_dir): continue return filespath = &apos;/home/caoda/Hodge_work_space/videos_data/videos_201712&apos;list_id = []f_list_id = open(&quot;list_id.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f_list_id.read()list_id = eval(a)f_list_id.close()print(&apos;读取list_id成功，现有&apos; + str(len(list_id)) + &apos;条数据&apos;)list_path = [&apos;07&apos;, &apos;08&apos;, &apos;09&apos;, &apos;10&apos;, &apos;11&apos;, &apos;12&apos;, &apos;13&apos;, &apos;14&apos;, &apos;15&apos;, &apos;16&apos;, &apos;18&apos;, &apos;19&apos;, &apos;20&apos;, &apos;21&apos;, &apos;24&apos;]for i in list_path: list_id += file_name(path + i) # print(path + str(i))print(&apos;总视频数：&apos; + str(len(list_id))) # 121117条数据-下载失败条数# 去除提取失败与剩余条数f_extract_fail = open(&quot;extract_fail&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)i = 0while 1: line_extract_fail = f_extract_fail.readline() if not line_extract_fail: break else: line_extract_fail = line_extract_fail.replace(&apos;
&apos;, &apos;&apos;) if (line_extract_fail in list_id): list_id.remove(line_extract_fail) i += 1print(&apos;清理&apos; + str(i) + &apos;条数据
最后总数据&apos; + str(len(list_id)))f_list_id = open(&quot;list_id.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_id.write(str(list_id))f_list_id.close()list_id.clear() 词频统计根据list_id和121117长度的final_hashs.txt对最终数据做词频统计写入count_hash.txt count.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100# 统计hash总数与词频import collectionsimport redef get_id(template): rule = r&apos;(.*?)::::&apos; slot_list = re.findall(rule, template) return slot_listdef get_text(template): rule = r&apos;::::(.*?)
&apos; slot_list = re.findall(rule, template) return slot_listdef get_list_or_dict(path): f = open(path, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) a = f.read() dict_or_list = eval(a) f.close() return dict_or_listlist_id = get_list_or_dict(&apos;list_id.txt&apos;)print(&apos;list_id长度&apos; + str(len(list_id)))f_id_hash_final = open(&quot;id_hash_final.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f = open(&quot;final_hashs.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)dict_id_hash = &#123;&#125;while 1: line_txt = f.readline() if not line_txt: break else: dict_id_hash[get_id(line_txt)[0]] = get_text(line_txt)[0]f.close()print(&apos;dict_id_hash长度&apos; + str(len(dict_id_hash))) # 121117f_dict_id_hash = open(&quot;dict_id_hash.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_hash.write(str(dict_id_hash))f_dict_id_hash.close()for id in list_id: id = id.replace(&apos;.mp4&apos;, &apos;&apos;) f_id_hash_final.write(id + &apos;::::&apos; + dict_id_hash[id] + &apos;
&apos;)f_id_hash_final.close()f_id_hash_final = open(&quot;id_hash_final.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_count_hash = open(&quot;count_hash.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def subString1(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListslotList = []i = 1# for i in range(0,3):while 1: line_id_hash = f_id_hash_final.readline() if not line_id_hash: break else: # print() slotList += subString1(line_id_hash) # 将所有HashTag存进list# print(slotList)result = collections.Counter(slotList) # 词频统计# ss = str(result) #词频统计结果转换成字符串并存文件# f_handle_hash.write(ss)# print(result.most_common(100)) 查看统计结果前100名for each in result.most_common(): ss = str(each) # 词频统计结果转换成字符串并存文件 f_count_hash.write(ss + &apos;
&apos;) # print(ss)f_id_hash_final.close()f_count_hash.close() 截取指定长度数据根据词频统计截取hash词频不小于5的数据存入id_hash count_num_hash.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970import redef getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef get_list_or_dict(path): f = open(path, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) a = f.read() dict_or_list = eval(a) f.close() return dict_or_listf_count_hash = open(&quot;count_hash.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)# f_list_count_hash = open(&quot;list_count_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)list_hash = []flag_hash_line = 0while 1: line_hash = f_count_hash.readline() if not line_hash: break else: rule1 = r&quot;&apos;(.*?)&apos;&quot; rule2 = r&apos;&quot;(.*?)&quot;&apos; rule3 = r&apos; (.*?)\)&apos; try: slotList = re.findall(rule1, line_hash) hash_num = re.findall(rule3, line_hash) if int(hash_num[0]) == 4: break else: list_hash.append(str(slotList[0])) flag_hash_line += 1 except IndexError: slotList = re.findall(rule2, line_hash) list_hash.append(str(slotList[0])) flag_hash_line += 1print(flag_hash_line)list_id = get_list_or_dict(&apos;list_id.txt&apos;)print(len(list_id))dict_id_hash = get_list_or_dict(&apos;dict_id_hash.txt&apos;)print(len(dict_id_hash))f_id_hash = open(&quot;id_hash&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)i = 0for id in list_id: id = str(id).replace(&apos;.mp4&apos;, &apos;&apos;) # print(id) line_list_hash = dict_id_hash[id].split(&apos; &apos;) # print(line_list_hash) line_hash_new = &apos;&apos; for hash in line_list_hash: hash = str(hash).replace(&apos;#&apos;, &apos;&apos;) if hash in list_hash: line_hash_new += &apos;#&apos; + hash + &apos; &apos; if line_hash_new != &apos;&apos;: # print(&apos;空：&apos; + id) # else: f_id_hash.write(id+&apos;::::&apos;+line_hash_new+&apos;
&apos;) i += 1 if (i % 10000 == 0): print(i)f_id_hash.close()print(i) 最终处理获得118684长度的id_hash文件 清理数据根据id_error文件从119120条分割后文件集中删除不合法数据 clean_extract_data.py12345678910111213141516171819202122232425262728293031323334353637383940414243import reimport osimport shutildef get_id(template): rule = r&apos;(.*?)::::&apos; slot_list = re.findall(rule, template) return slot_listdef get_list_or_dict(path): f = open(path, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) a = f.read() dict_or_list = eval(a) f.close() return dict_or_listdict_id_num = get_list_or_dict(&apos;dict_id_num.txt&apos;)print(len(dict_id_num))list_id_error = []f_id_error = open(&apos;id_error&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_id_error = f_id_error.readline() if not line_id_error: break else: list_id_error.append(dict_id_num[line_id_error.replace(&apos;
&apos;,&apos;&apos;)])print(len(list_id_error))path = &apos;/home/caoda/Hodge_work_space/dataset/dataset&apos;ii = 0for i in range(1, 16): list_extract_num = os.listdir(path + str(i)) for num in list_extract_num: if(num in list_id_error): try: shutil.rmtree(path+str(i)+&apos;/&apos;+num) # print(path+str(i)+&apos;/&apos;+num) except: print(&apos;删除出错&apos;) ii += len(os.listdir(path + str(i)))print(ii) 到目前为止数据集已准备并分割完毕。数据集与代码，发布在github.

字符串截取字符串截取指定两个符号间的字符串返回所有符合结果的list12345678910111213141516171819202122def get_list_hash(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotList 1234def get_text(template): rule = r&apos;:::(.*?)
&apos; slot_list = re.findall(rule, template) return slot_list 判断是否为英文字母1234567#解决.isalpha()方法对（unicode string，string.isalpha会根据字符串中的字符是否属于Unicode编码的LETTER区域来判断是否都由字母组成。# 所以得出的结果为True，不一定表示只有26个英文字母。）def is_alpha(word): try: return word.encode(&apos;ascii&apos;).isalpha() except UnicodeEncodeError: return False 文件操作创建文件夹1234567891011121314151617181920212223def mkdir(path): # 去除首位空格 path = path.strip() # 去除尾部 \ 符号 path = path.rstrip(&quot;/&quot;) # 判断路径是否存在 # 存在 True # 不存在 False isExists = os.path.exists(path) # 判断结果 if not isExists: # 如果不存在则创建目录 # 创建目录操作函数 os.makedirs(path) print(str(path) + &apos; 创建成功&apos;) return True else: # 如果目录存在则不创建，并提示目录已存在 print(str(path) + &apos; 目录已存在&apos;) return False 读取文件读取并按行遍历文件1234567f_video_text = open(&quot;video_text.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_video_text = f_video_text.readline() if not line_video_text: break else: do something 读取文件夹下所有文件名，返回list1234def get_list_file_name(file_dir): # 获取视频名list for root, dirs, files in os.walk(file_dir): continue return files 获取文件行数12345678910def get_lines(file_name): count = 0 thefile = open(file_name, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) while True: buffer = thefile.read(1024 * 8192) if not buffer: break count += buffer.count(&apos;
&apos;) thefile.close() return count 读取文件dict or list123456def get_list_or_dict(path): f = open(path,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) a = f.read() dict_or_list = eval(a) f.close() return dict_or_list txt文件数据写成dict or list文件1234567891011121314def write_list_or_dict(path_txt,path_dict_or_list_txt): f = open(path_txt,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) while 1: line_txt = f.readline() if not line_txt: break else: handle list_or_dict[id] = content f.close() f = open(path_dict_or_list_txt, &apos;w&apos; , encoding=&apos;utf8&apos; , errors=&apos;ignore&apos;) f.write(str(list_or_dict)) f.close print(&apos;写入成功&apos;) 获取视频或音频时长获取视频或音频时长，需要安装ffmpeg12345678def get_time(filename): command = &apos;ffprobe -loglevel quiet -print_format json -show_format -show_streams -i &apos; + filename result = subprocess.Popen(command, shell=True, stdout=subprocess.PIPE, stderr=subprocess.STDOUT) out = result.stdout.read() temp = str(out.decode(&apos;utf-8&apos;)) data = json.loads(temp)[&quot;format&quot;][&apos;duration&apos;] return data

需求视频下载下来后，需要对每个视频提取12个关键帧，提取每个视频的音频并等分为6段，获取每个视频的text。三者分别保存在以id命名的文件夹下以images/audios/texts命名的文件夹下。 准备工作扫描存放所有视频的文件夹，将所有视频名存储为list_videos_name并写入文件list_videos.txt get_videos_list.py1234567891011121314# 获取要提取关键帧的所有视频的名字存储在list_videos_name并写入文件list_videos_name.txtimport osdef file_name(file_dir): # 获取视频名list for root, dirs, files in os.walk(file_dir): continue return filesvideos_path = &apos;D:/videos/videos_20171207&apos; # 填写存放视频的文件夹路径list_videos_name = file_name(videos_path)f_list_videos_name = open(&quot;list_videos.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_videos_name.write(str(list_videos_name))f_list_videos_name.close() 为了获取视频text，须对之前处理获得的final_texts.txt读取获得dict_id_text并存储为dict_id_text.txt get_dict_id_text.py123456789101112131415161718192021222324252627# 读取final_texts.txt，生成字典dict_id_textimport ref_id_texts = open(&quot;final_texts.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def get_text(template): rule = r&apos;::::(.*?)
&apos; slot_list = re.findall(rule, template) return slot_listdef get_id(template): rule = r&apos;(.*?)::::&apos; slot_list = re.findall(rule, template) return slot_listdict_id_text = &#123;&#125;while 1: line_id_text = f_id_texts.readline() if not line_id_text: break else: dict_id_text[str(get_id(line_id_text)[0])] = str(get_text(line_id_text)[0])f_id_texts.close()f_id_texts = open(&quot;dict_id_text.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_texts.write(str(dict_id_text)) 细节 因为要处理的数据量较大，要考虑到程序可随时终止再继续运行。故加入四个日志文件 extract_ok.txt：记录所有处理成功的视频 extract_ok_this_time.txt：记录每次任务处理成功的视频 video_error.txt：记录所有处理失败的视频 video_error_this_time.txt：记录每次任务处理失败的视频 在每次任务开始处理视频前将日志文件整合并将处理成功的视频从list_videos中删除即可 视频帧提取用的cv2包，视频的音频提取和音频的分割用的第三方工具ffmpeg 音频分割后发现每段音频间有重叠部分，故应采用精准分割1ffmpeg -y -vn -ss start_time -t 持续时间(00:00:00.900) -i 原文件路径 -acodec copy 生成文件路径 get_final_dataset.# 配置video_path、mkpath_images和mkpath_audios内容import cv2import osimport subprocessimport jsondef mkdir(path): # 去除首位空格 path = path.strip() # 去除尾部 \ 符号 path = path.rstrip(&quot;/&quot;) # 判断路径是否存在 # 存在 True # 不存在 False isExists = os.path.exists(path) # 判断结果 if not isExists: # 如果不存在则创建目录 # 创建目录操作函数 os.makedirs(path) print(str(path) + &apos; 创建成功&apos;) return True else: # 如果目录存在则不创建，并提示目录已存在 print(str(path) + &apos; 目录已存在&apos;) return Falsedef get_lines(file_name): #获取文件行数 count = 0 thefile = open(file_name, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) while True: buffer = thefile.read(1024 * 8192) if not buffer: break count += buffer.count(&apos;
&apos;) thefile.close() return countdef get_time(filename): #获取视频或音频时长 command = [&quot;ffprobe.exe&quot;, &quot;-loglevel&quot;, &quot;quiet&quot;, &quot;-print_format&quot;, &quot;json&quot;, &quot;-show_format&quot;, &quot;-show_streams&quot;, &quot;-i&quot;, filename] result = subprocess.Popen(command, shell=True, stdout=subprocess.PIPE, stderr=subprocess.STDOUT) out = result.stdout.read() temp = str(out.decode(&apos;utf-8&apos;)) data = json.loads(temp)[&quot;format&quot;][&apos;duration&apos;] return datadef get_flag_list(flag): #获取flag每一位上数字 list_flag = [] while flag: get_num = flag % 10 list_flag.append(int(get_num)) flag = (flag - get_num) / 10 return list_flagf_list_videos = open(&quot;list_videos.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f_list_videos.read()list_videos = eval(a)f_list_videos.close()print(&apos;list_videos.txt读取成功&apos;)f_extract_ok = open(&quot;extract_ok.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_extract_ok_this_time = open(&quot;extract_ok_this_time.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_extract_ok_this_time = f_extract_ok_this_time.readline() if not line_extract_ok_this_time: break else: list_videos.remove(str(line_extract_ok_this_time).replace(&apos;
&apos;, &apos;&apos;) + &apos;.mp4&apos;) # 更新未抽取videos f_extract_ok.write(str(line_extract_ok_this_time)) # 更新已抽取videosf_extract_ok_this_time.close()f_extract_ok.close()f_list_videos = open(&quot;list_videos.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_videos.write(str(list_videos))f_list_videos.close()print(&quot;list_videos清理已抽取视频id成功&quot;)print(&quot;extract_ok添加已抽取视频id成功&quot;)print(&quot;共剩余&quot; + str(len(list_videos)) + &apos;条未抽取&apos;)print(&quot;总共已抽取&quot; + str(get_lines(&apos;extract_ok.txt&apos;)) + &apos;条视频&apos;)f = open(&quot;extract_ok_this_time.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) # 释放空间f.close()f_video_error = open(&quot;video_error.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_error_this_time = open(&quot;video_error_this_time.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_video_error_this_time = f_video_error_this_time.readline() if not line_video_error_this_time: break else: f_video_error.write(str(line_video_error_this_time) + &apos;
&apos;) # 更新失败videosf_video_error_this_time.close()f_video_error.close()print(&quot;video_error增加错误videos成功&quot;)print(&quot;共有&quot; + str(get_lines(&apos;video_error.txt&apos;)) + &apos;条视频抽取错误&apos;)f = open(&quot;video_error_this_time.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) # 释放空间.f.close()f = open(&quot;dict_id_text.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()dict_id_text = eval(a)f.close()print(&quot;dict_id_text读取成功
&quot;)print(&apos;---开始抽取---&apos;)flag = 1for video_name in list_videos: try: video_path = &apos;D:/videos/videos_20171207/&apos; + str(video_name) # 配置视频文件夹路径 video_cap = cv2.VideoCapture(video_path) frame_count = 0 all_frames = [] while (True): ret, frame = video_cap.read() if ret is False: break all_frames.append(frame) # 视频所有帧存list frame_count = frame_count + 1 # 帧数 i = 0 flag = int(frame_count / 12) video_name = video_name.replace(&quot;.mp4&quot;, &quot;&quot;) mkpath_images = &quot;I:/images/&quot; + video_name + &apos;/images&apos; # 路径全英文---存12帧图片文件夹路径 mkdir(mkpath_images) mkpath_audios = &quot;I:/images/&quot; + video_name + &apos;/audios&apos; # 路径全英文---存音频文件夹路径 mkdir(mkpath_audios) mkpath_texts = &quot;I:/images/&quot; + video_name + &apos;/texts&apos; # 路径全英文---存文本文件夹路径 mkdir(mkpath_texts) for frame in all_frames: i = i + 1 if (i % flag == 0 and i &lt;= flag * 12): path = mkpath_images + &apos;/&apos; + str(int(i / flag)) + &apos;.jpg&apos; cv2.imwrite(path, frame) # 存储为图像 audio_path = mkpath_audios + &apos;/&apos; + video_name + &apos;.mp3&apos; cmd = &apos;ffmpeg -i &apos; + video_path + &apos; -f mp3 -vn &apos; + audio_path + &apos; -loglevel quiet -y&apos; os.system(cmd) # 提取音频 video_time = get_time(video_path) # 音频分段 video_time = int(float(video_time) * 1000) flag = int(video_time / 6) list_flag = get_flag_list(flag) every_time = str(list_flag[2]) + str(list_flag[1]) + str(list_flag[0]) start = 0 end = flag for i in range(1, 7): cmd = &apos;ffmpeg -y -vn -ss 00:00:0&apos; + str(int(start / 1000)) + &apos;.&apos; + str( int(start % 1000)) + &apos; -t 00:00:0&apos; + str( int( flag / 1000)) + &apos;.&apos; + every_time + &apos; -i &apos; + audio_path + &apos; -codec copy &apos; + mkpath_audios + &apos;/&apos; + str( i) + &apos;.mp3&apos; + &apos; -loglevel quiet&apos; os.system(cmd) start += flag end += flag f_video_text = open(mkpath_texts+&apos;/text.txt&apos;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_video_text.write(str(dict_id_text[video_name])+&apos;
&apos;) f_video_text.close() print(&apos;。。。。。&apos;) f_extract_ok_this_time = open(&quot;extract_ok_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_extract_ok_this_time.write(str(video_name) + &apos;
&apos;) f_extract_ok_this_time.close() flag += 1 except (TimeoutError): print(&apos;----video打开失败----&apos;) f_video_error_this_time = open(&quot;video_error_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_video_error_this_time.write(str(video_name) + &apos;
&apos;) f_video_error_this_time.close() print(&apos;本次已抽取&apos; + str(get_lines(&apos;extract_ok_this_time.txt&apos;)) + &apos;条，本次抽取videos错误&apos; + str( get_lines(&apos;video_error_this_time.txt&apos;)) + &apos;条&apos;) # print(dict_video_error_this_time) print(&apos;已保存并跳过此条video_id，抽取继续--&gt;&apos;) if (flag % 1000 == 0): print(&apos;本次已抽取&apos; + flag + &apos;条视频&apos;)print(&quot;****下载抽取完成****&quot;) 小结到目前为止，读取所有的视频并保存其帧、音频、文本数据。数据集与代码，发布在github.

需求现在拥有了一个121117条 id::::url 的final_hashs.txt文件需要读取里面的url并下载对应的视频，有如下要求： 随时可手动停止下载，再次开始下载可继续上次任务 保存下载成功的视频id，保存下载失败(链接失效或下载超时)的视频id::::url 自定义下载路径download_2.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677787980818283848586878889#可间断性地下载final_urls.txt的链接获得视频集import urllib.requestdef getLines(file_name): #获取文件行数 count = 0 thefile = open(file_name, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) while True: buffer = thefile.read(1024 * 8192) if not buffer: break count += buffer.count(&apos;
&apos;) thefile.close() return countdict_id_url = &#123;&#125;f = open(&quot;dict_id_url.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()dict_id_url = eval(a)f.close()print(&quot;dict_id_url读取成功&quot;) #读取剩余urlsf_down_ok = open(&quot;down_ok.txt&quot;,&apos;a&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_down_ok_this_time = open(&quot;down_ok_this_time.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_down_ok_this_time = f_down_ok_this_time.readline() if not line_down_ok_this_time: break else: line_down_ok_this_time = line_down_ok_this_time.replace(&apos;
&apos;,&apos;&apos;) del dict_id_url[str(line_down_ok_this_time)] #更新未下载urls f_down_ok.write(str(line_down_ok_this_time)+&apos;
&apos;) #更新已下载urlsf_down_ok_this_time.close()f_down_ok.close()f_dict_id_url = open(&quot;dict_id_url.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) #保存未下载的urlsf_dict_id_url.write(str(dict_id_url))f_dict_id_url.close()print(&quot;dict_id_url清理已下载urls成功&quot;)print(&quot;down_ok添加已下载urls成功&quot;)print(&quot;共剩余&quot;+str(len(dict_id_url))+&apos;条未下载&apos;)print(&quot;总共已下载&quot;+str(getLines(&apos;down_ok.txt&apos;))+&apos;条视频&apos;)f = open(&quot;down_ok_this_time.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) #清空文本f.close()f_url_error = open(&quot;url_error.txt&quot;,&apos;a&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_url_error_this_time = open(&quot;url_error_this_time.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_url_error_this_time = f_url_error_this_time.readline() if not line_url_error_this_time: break else: f_url_error.write(str(line_url_error_this_time)) #更新失效urlsf_url_error_this_time.close()f_url_error.close()print(&quot;url_error增加错误urls成功&quot;)print(&quot;共有&quot;+str(getLines(&apos;url_error.txt&apos;))+&apos;条视频链接错误&apos;)f = open(&quot;url_error_this_time.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) #清空文本f.close()print(&apos;---开始下载---&apos;)flag = 1for key in dict_id_url: url = str(dict_id_url[key]) try: if &apos;.mp4?&apos; in url: video_name = str(key)+&apos;.mp4&apos; #视频保存路径 urllib.request.urlretrieve(url, video_name) #下载 f_down_ok_this_time = open(&quot;down_ok_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_down_ok_this_time.write(str(key)+&apos;
&apos;) f_down_ok_this_time.close() print(&apos;。。。。。&apos;) #下载成功一条打一个标记 flag += 1 else: f_url_error_this_time = open(&quot;url_error_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_url_error_this_time.write(str(key)+&apos;::::&apos;+dict_id_url[key]+&apos;
&apos;) f_url_error_this_time.close() except (TimeoutError,urllib.error.URLError): print(&apos;----url失效，下载超时----&apos;) f_url_error_this_time = open(&quot;url_error_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_url_error_this_time.write(str(key) + &apos;::::&apos; + dict_id_url[key] + &apos;
&apos;) f_url_error_this_time.close() print(&apos;本次已下载&apos;+str(getLines(&apos;down_ok_this_time.txt&apos;))+&apos;条，本次下载url错误&apos;+str(getLines(&apos;url_error_this_time.txt&apos;))+&apos;条&apos;) print(&apos;已保存并跳过此条url，下载继续--&gt;&apos;) if(flag%1000==0): print(&apos;本次已下载&apos;+flag+&apos;条视频&apos;)print(&quot;****下载全部完成****&quot;) 小结数据集与代码，发布在github.

需求现在拥有了一一对应的id::::text（video_text_hash.txt）和id::::url（video_url_hash.txt）。需求是永远递增的嘛~~~将video_text_hash.txt中text内容的#hash拿出来，单独存成id::::text（id_text.txt）和id::::hash（id_hash.txt）PS:拿完#hash后剩下的text若为空则删除此条目 handle_text.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374import re#根据video_text_hash.txt将hash提取出来获得id_hash.txt和剩下的id_text.txt其中排除剩余为空的id_text_void.txtf_video_texts = open(&quot;video_text_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_text = open(&quot;id_text.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_text_void = open(&quot;id_text_void.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_hash = open(&quot;id_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def get_hashs(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListdef getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotList# for i in range(1,20):ii=0while 1: line_video_text = f_video_texts.readline() list_hash = [] if not line_video_text: break else: try: list_hash = get_hashs(line_video_text) #hash组成一个list list_text = getText(line_video_text) #text组成list str_text = str(list_text[0])+&apos;
&apos; str_hashs = &apos;&apos; for hash in list_hash: #遍历每句的每个hash str_hash1 = &apos;#&apos;+str(hash)+&apos; &apos; str_hashs += str(str_hash1) str_hash2 = &apos;#&apos; + str(hash) + &apos;
&apos; #还原hash str_text = str_text.replace(str_hash1,&quot;&quot;) #删除hash str_text = str_text.replace(str_hash2, &quot;
&quot;) except IndexError: print(&quot;error&quot;) if(str_text != &apos;
&apos;): f_text.write(str(getId(line_video_text)[0])+&apos;::::&apos;+str_text) f_hash.write(str(getId(line_video_text)[0])+&apos;::::&apos;+str_hashs+&apos;
&apos;) else: f_text_void.write(str(getId(line_video_text)[0])+&apos;
&apos;) ii+=1 if(ii%10000==0): print(ii)f_video_texts.close()f_text.close()f_text_void.close()f_hash.close() text处理对于id_text.txt里的text，还需要做以下操作，1、去除非英文字符。2、去除停顿词。3、小写化text。得到id_text_final.txt和被剔除的剩余为空的id存到id_text_final_void.txt。同时顺便得到清理后的id::::hashs文件id_hash_final.txt（顺便小写化） handle_text_final.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103import re#根据id_text.txt做文本处理获得id_text_final.txt和排除剩余为空的id_text_final_void.txt#顺便得到清理后的id::::hashs文件id_hash_final.txtf_video_texts = open(&quot;id_text.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_stop_word = open(&quot;stop_word.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_hash = open(&quot;id_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_text_final = open(&quot;id_text_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_text_final_void = open(&quot;id_text_final_void.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_hash_final = open(&quot;id_hash_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotList#解决.isalpha()方法对（unicode string，string.isalpha会根据字符串中的字符是否属于Unicode编码的LETTER区域来判断是否都由字母组成。# 所以得出的结果为True，不一定表示只有26个英文字母。）def isAlpha(word): try: return word.encode(&apos;ascii&apos;).isalpha() except UnicodeEncodeError: return Falselist_stop_word = []while 1: line_stop_word = f_stop_word.readline() if not line_stop_word: break else: list_stop_word.append(str(line_stop_word).replace(&quot;
&quot;,&apos;&apos;).lower())print(&quot;停用词列表生成成功&quot;)dict_hash = &#123;&#125;while 1: line_hash = f_id_hash.readline() if not line_hash: break else: dict_hash[getId(line_hash)[0]] = getText(line_hash)[0]print(&quot;hash字典生成成功&quot;)ii=0# for i in range(1,3):while 1: line_video_text = f_video_texts.readline() list_word = [] if not line_video_text: break else: try: list_text = str(getText(line_video_text)[0]) text_final = &apos;&apos; for s in list_text: if isAlpha(s): text_final += s elif s==&apos; &apos;: text_final += s #text字符串，包含多余空格 # print(text_final) list_word = text_final.split(&apos; &apos;) #分词，包含空字符 text_final = &apos;&apos; for word in list_word: if word == &apos;&apos;: continue elif word not in list_stop_word: text_final += word+&apos; &apos; if text_final != &apos;&apos;: str_hash = dict_hash[getId(line_video_text)[0]] #清除非全英文字母的hash rule = r&apos;#(.*?) &apos; list_hashs = re.findall(rule, str_hash) str_hash = &apos;&apos; for hash in list_hashs: flag = 1 for s in hash: if isAlpha(s): continue else: flag = 0 break if flag: str_hash += &apos;#&apos;+hash+&apos; &apos; if str_hash != &apos;&apos;: f_id_text_final.write(getId(line_video_text)[0]+&apos;::::&apos;+text_final+&apos;
&apos;) #将去除空结果的id::::text写入id_text_final.txt f_id_hash_final.write(getId(line_video_text)[0]+&apos;::::&apos;+str_hash+&apos;
&apos;) else: f_id_text_final_void.write(getId(line_video_text)[0]+&apos;
&apos;) #将空白结果id写入text_final_void.txt except IndexError: print(&quot;error&quot;) ii+=1 if(ii%10000==0): print(ii)# print(len(list_1)) #data1的id listf_video_texts.close()f_stop_word.close()f_id_hash.close()f_id_text_final.close()f_id_text_final_void.close()f_id_hash_final.close() 统计hash词频根据id_hash_final.txt做hash的词频统计得到count_hash.txt count.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647# 统计hash总数与词频import collectionsimport ref_id_hash_final = open(&quot;id_hash_final.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_count_hash = open(&quot;count_hash.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def subString1(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListslotList = []i=1# for i in range(0,5):while 1: line_id_hash = f_id_hash_final.readline() if not line_id_hash: break else: slotList += subString1(line_id_hash) #将所有HashTag存进list# print(slotList)result = collections.Counter(slotList) #词频统计#ss = str(result) #词频统计结果转换成字符串并存文件# f_handle_hash.write(ss)#print(result.most_common(100)) 查看统计结果前100名for each in result.most_common(): ss = str(each) #词频统计结果转换成字符串并存文件 f_count_hash.write(ss+&apos;
&apos;) #print(ss)f_id_hash_final.close()f_count_hash.close() 截取指定长度数据集遍历id_hash_final.txt里的hash，走到最后一个频率为5的hash（premiosjuventud）停止首先生成对应的list与dict以供快速读取 get_list_or_dict.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182838485868788import re#id_text_final--&gt;dict_id_text_final#id_hash_final--&gt;dict_id_hash_final#count_hash--&gt;list_count_hash#video_url_hash--&gt;dict_id_urlf_id_text_final = open(&quot;id_text_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_text_final = open(&quot;dict_id_text_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_hash_final = open(&quot;id_hash_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_hash_final = open(&quot;dict_id_hash_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_count_hash = open(&quot;count_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_count_hash = open(&quot;list_count_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_hash = open(&quot;video_url_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_url = open(&quot;dict_id_url.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotListlist_hash = []while 1: line_hash = f_count_hash.readline() if not line_hash: break else: rule1 = r&quot;&apos;(.*?)&apos;&quot; rule2 = r&apos;&quot;(.*?)&quot;&apos; try: slotList = re.findall(rule1, line_hash) list_hash.append(str(slotList[0])) except IndexError: slotList = re.findall(rule2, line_hash) list_hash.append(str(slotList[0]))f_list_count_hash.write(str(list_hash))# print(len(list_1)) #data1的id listdict_id_text_final = &#123;&#125;dict_id_hash_final = &#123;&#125;ii=1while 1: line_id_text = f_id_text_final.readline() line_id_hash = f_id_hash_final.readline() if not line_id_text: break else: each_id = getId(line_id_text) each_text = getText(line_id_text) dict_id_text_final[each_id[0]] = each_text[0] each_id = getId(line_id_hash) each_text = getText(line_id_hash) dict_id_hash_final[each_id[0]] = each_text[0] ii += 1 if (ii % 50000 == 0): print(ii)f_dict_id_text_final.write(str(dict_id_text_final))f_dict_id_hash_final.write(str(dict_id_hash_final))# print(dict_id_text_final[&apos;980744748887429120&apos;]) #data2的dict &#123;id:text&#125;# print(dict_id_hash_final[&apos;980744748887429120&apos;])dict_id_url = &#123;&#125;ii=1while 1: line_id_url = f_video_url_hash.readline() if not line_id_url: break else: each_id = getId(line_id_url) each_text = getText(line_id_url) dict_id_url[each_id[0]] = each_text[0] ii += 1 if (ii % 50000 == 0): print(ii)f_dict_id_url.write(str(dict_id_url))# print(dict_id_url[&apos;980744748887429120&apos;]) #data2的dict &#123;id:text&#125;f_id_text_final.close()f_dict_id_text_final.close()f_id_hash_final.close()f_dict_id_hash_final.close()f_count_hash.close()f_list_count_hash.close()f_video_url_hash.close()f_dict_id_url.close() 最后得到一定数量的数据集final_id_texts/hashs/urls.txt get_final_urls.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576import re#根据count_hash.txt和id_hash_final.txt获得最终需要的一定数量的数据集final_id_texts/hashs/urls.txtf_dict_id_text_final = open(&quot;dict_id_text_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_hash_final = open(&quot;dict_id_hash_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_count_hash = open(&quot;list_count_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_url = open(&quot;dict_id_url.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_final_texts = open(&quot;final_texts.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_final_hashs = open(&quot;final_hashs.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_final_urls = open(&quot;final_urls.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotListlist_hash = []f = open(&quot;list_count_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()list_hash = eval(a)f.close()print(&quot;list_count_hash读取成功
